class Solution {
public:
    int countDigitOne(int n) {
        int res = 0;
        for (int i = 1; i <= n; i++) {
            res += count(i);
        }
        return res;
    }
    int count(int num) {
        int res = 0;
        int cur = num;
        while (cur > 0) {
            if (cur % 10 == 1) res += (cur / 10 >= 1) ? cur / 10 + 1 : 1;
            cur /= 10;
        }
        return res;
    }
};
```
